import { z } from "zod";
import type {
  FormConfig,
  FileFieldConfig,
  TextFieldConfig,
  FormFieldConfig,
  NumberFieldConfig,
  TextareaFieldConfig,
  MultiselectFieldConfig,
} from "../types/types";

/** Extract all fields from a form config */
export function extractFields(config: FormConfig): FormFieldConfig[] {
  return config.sections.flatMap((section) => section.fields);
}

/**
 * Evaluate a field's condition against current form values.
 * Returns true if the field should be VISIBLE (and thus required).
 */
export function evaluateCondition(
  condition: FormFieldConfig["condition"],
  formValues: Record<string, unknown>
): boolean {
  if (!condition) return true;
  const { field, operator, value } = condition;
  const condVal = formValues[field];
  switch (operator) {
    case "equals": return String(condVal) === String(value);
    case "notEquals": return String(condVal) !== String(value);
    case "contains": return String(condVal || "").includes(value || "");
    case "notEmpty": return !!condVal && condVal !== "";
    case "empty": return !condVal || condVal === "";
    case "in": return (value || "").split(",").map((v: string) => v.trim()).includes(String(condVal));
    case "isTrue": return condVal === true || condVal === "true";
    case "isFalse": return condVal === false || condVal === "false" || !condVal;
    default: return true;
  }
}

/**
 * Build a Zod schema dynamically from field configs at runtime.
 * Pass optional `formValues` to make conditional fields properly required/optional
 * based on the current form state — fields hidden by a condition become fully optional.
 *
 * Usage in your page component:
 *   const schema = useMemo(() => buildZodSchema(extractFields(config)), [config]);
 *   <ReactHookForm config={config} schema={schema} onSubmit={handleSubmit} />
 */
export function buildZodSchema(
  fields: FormFieldConfig[]
): z.ZodObject<Record<string, z.ZodTypeAny>> {
  const shape: Record<string, z.ZodTypeAny> = {};
  const conditionalRequiredFields: {
    name: string;
    label: string;
    condition: NonNullable<FormFieldConfig["condition"]>;
    type: string;
  }[] = [];

  for (const field of fields) {
    let fieldSchema: z.ZodTypeAny;
    const isConditionalRequired = !!field.condition && !!field.required;

    switch (field.type) {
      case "text":
      case "password":
      case "tel":
      case "url":
        fieldSchema = z.string();
        if (field.required && !isConditionalRequired) {
          fieldSchema = (fieldSchema as z.ZodString).min(1, `${field.label || field.name} is required`);
        }
        if ((field as TextFieldConfig).minLength) {
          fieldSchema = (fieldSchema as z.ZodString).min(
            (field as TextFieldConfig).minLength!,
            `Minimum ${(field as TextFieldConfig).minLength} characters`
          );
        }
        if ((field as TextFieldConfig).maxLength) {
          fieldSchema = (fieldSchema as z.ZodString).max(
            (field as TextFieldConfig).maxLength!,
            `Maximum ${(field as TextFieldConfig).maxLength} characters`
          );
        }
        break;

      case "email":
        fieldSchema =
          field.required && !isConditionalRequired
            ? z.email("Invalid email address").min(1, `${field.label || field.name} is required`)
            : z.preprocess(
                (v) => (v === "" || v === null || v === undefined ? undefined : v),
                z.email("Invalid email address").optional(),
              );
        break;

      case "number": {
        const toNum = (val: unknown) =>
          val === "" || val === null || val === undefined ? undefined : Number(val);

        const numField = field as NumberFieldConfig;
        let baseNum = z.number({ message: "Must be a number" });
        if (numField.min !== undefined)
          baseNum = baseNum.min(numField.min, `Minimum value is ${numField.min}`);
        if (numField.max !== undefined)
          baseNum = baseNum.max(numField.max, `Maximum value is ${numField.max}`);

        if (field.required && !isConditionalRequired) {
          fieldSchema = z.preprocess(
            (val) => (val === "" || val === null || val === undefined ? undefined : Number(val)),
            baseNum
          );
        } else {
          fieldSchema = z.preprocess(toNum, baseNum.optional());
        }
        break;
      }

      case "textarea":
        fieldSchema = z.string();
        if (field.required && !isConditionalRequired) {
          fieldSchema = (fieldSchema as z.ZodString).min(1, `${field.label || field.name} is required`);
        }
        if ((field as TextareaFieldConfig).minLength) {
          fieldSchema = (fieldSchema as z.ZodString).min(
            (field as TextareaFieldConfig).minLength!,
            `Minimum ${(field as TextareaFieldConfig).minLength} characters`
          );
        }
        if ((field as TextareaFieldConfig).maxLength) {
          fieldSchema = (fieldSchema as z.ZodString).max(
            (field as TextareaFieldConfig).maxLength!,
            `Maximum ${(field as TextareaFieldConfig).maxLength} characters`
          );
        }
        break;

      case "select":
      case "combobox":
      case "asyncselect":
      case "asynccombobox":
      case "infiniteselect":
      case "infinitecombobox":
        fieldSchema = z.string();
        if (field.required && !isConditionalRequired) {
          fieldSchema = (fieldSchema as z.ZodString).min(1, `${field.label || field.name} is required`);
        }
        break;

      case "radio":
        fieldSchema = z.string();
        if (field.required && !isConditionalRequired) {
          fieldSchema = (fieldSchema as z.ZodString).min(1, `${field.label || field.name} is required`);
        }
        break;

      case "checkbox":
      case "switch":
        fieldSchema = z.boolean();
        break;

      case "checkboxgroup":
        fieldSchema = z.array(z.string());
        break;

      case "switchgroup":
        fieldSchema = z.record(z.string(), z.boolean());
        break;

      case "multiselect":
      case "multicombobox":
      case "asyncmultiselect":
      case "asyncmulticombobox":
      case "infinitemultiselect":
      case "infinitemulticombobox":
        fieldSchema = z.array(z.string());
        if ((field as MultiselectFieldConfig).maxItems) {
          fieldSchema = (fieldSchema as z.ZodArray<z.ZodString>).max(
            (field as MultiselectFieldConfig).maxItems!,
            `Maximum ${(field as MultiselectFieldConfig).maxItems} items`
          );
        }
        break;

      case "file": {
        const fileField = field as FileFieldConfig;
        if (fileField.multiple) {
          fieldSchema = z.array(z.instanceof(File)).refine(
            (files) => {
              if (fileField.validation?.maxFiles && files.length > fileField.validation.maxFiles) return false;
              if (fileField.validation?.maxSize) return files.every((f) => f.size <= fileField.validation!.maxSize!);
              return true;
            },
            { message: fileField.validation?.maxSize ? `File size must be less than ${Math.round(fileField.validation.maxSize / 1024 / 1024)}MB` : "Invalid file" }
          );
        } else {
          fieldSchema = z.instanceof(File).optional().refine(
            (file) => {
              if (!file) return true;
              if (fileField.validation?.maxSize && file.size > fileField.validation.maxSize) return false;
              return true;
            },
            { message: fileField.validation?.maxSize ? `File size must be less than ${Math.round(fileField.validation.maxSize / 1024 / 1024)}MB` : "Invalid file" }
          );
        }
        break;
      }

      case "date":
        fieldSchema = z.string();
        if (field.required && !isConditionalRequired) {
          fieldSchema = (fieldSchema as z.ZodString).min(1, `${field.label || field.name} is required`);
        }
        break;

      case "hidden":
        fieldSchema = z.string();
        break;

      default:
        fieldSchema = z.string();
    }

    // Conditional required fields are optional in the base shape
    // (superRefine handles the required check dynamically)
    if (isConditionalRequired) {
      conditionalRequiredFields.push({
        name: field.name,
        label: field.label || field.name,
        condition: field.condition!,
        type: field.type,
      });
      const isBoolType = field.type === "checkbox" || field.type === "switch";
      if (!isBoolType) {
        fieldSchema = fieldSchema.optional();
      }
    } else {
      // Non-conditional, non-required → optional (except booleans and numbers already handled)
      const isBoolType = field.type === "checkbox" || field.type === "switch";
      const isNumType = field.type === "number";
      if (!field.required && !isBoolType && !isNumType) {
        fieldSchema = fieldSchema.optional();
      }
    }

    shape[field.name] = fieldSchema;
  }

  const baseSchema = z.object(shape);

  // Add superRefine for conditional required fields
  if (conditionalRequiredFields.length > 0) {
    return baseSchema.superRefine((data, ctx) => {
      for (const crf of conditionalRequiredFields) {
        const isVisible = evaluateCondition(crf.condition, data as Record<string, unknown>);
        if (isVisible) {
          const val = (data as Record<string, unknown>)[crf.name];
          const isEmpty =
            val === undefined ||
            val === null ||
            (typeof val === "string" && val.length === 0) ||
            (Array.isArray(val) && val.length === 0);
          if (isEmpty) {
            ctx.addIssue({
              code: z.ZodIssueCode.custom,
              message: `${crf.label} is required`,
              path: [crf.name],
            });
          }
        }
      }
    });
  }

  return baseSchema;
}

/**
 * Generate compile-time Zod schema code from field config.
 * Produces a static formSchema.ts file string for full IDE type inference.
 */
export function generateZodSchemaCode(fields: FormFieldConfig[]): string {
  const lines: string[] = ['import { z } from "zod";', '', 'const baseSchema = z.object({'];

  // Collect conditional required fields for .superRefine()
  const conditionalRequiredFields: { name: string; label: string; condition: NonNullable<FormFieldConfig["condition"]> }[] = [];

  for (const field of fields) {
    let chain = '';
    // If field has a condition AND is required, make it optional in the base schema
    // and add a .superRefine() check instead
    const isConditionalRequired = !!field.condition && !!field.required;

    switch (field.type) {
      case "email":
        if (field.required && !isConditionalRequired) {
          chain = 'z.email("Invalid email").min(1, "' + (field.label || field.name) + ' is required")';
        } else {
          chain =
            'z.preprocess((v) => (v === "" || v === null || v === undefined ? undefined : v), z.email("Invalid email").optional())';
        }
        break;
      case "number":
        chain = 'z.coerce.number()';
        if ((field as NumberFieldConfig).min !== undefined) chain += `.min(${(field as NumberFieldConfig).min})`;
        if ((field as NumberFieldConfig).max !== undefined) chain += `.max(${(field as NumberFieldConfig).max})`;
        if (!field.required || isConditionalRequired) chain += '.optional()';
        break;
      case "checkbox":
      case "switch":
        chain = 'z.boolean()';
        break;
      case "checkboxgroup":
      case "multiselect":
      case "multicombobox":
      case "asyncmultiselect":
      case "asyncmulticombobox":
      case "infinitemultiselect":
      case "infinitemulticombobox":
        chain = 'z.array(z.string())';
        if ((field as MultiselectFieldConfig).maxItems) chain += `.max(${(field as MultiselectFieldConfig).maxItems})`;
        if (!field.required || isConditionalRequired) chain += '.optional()';
        break;
      case "switchgroup":
        chain = 'z.record(z.string(), z.boolean())';
        break;
      case "file":
        chain = 'z.instanceof(File).optional()';
        break;
      default:
        chain = 'z.string()';
        if (field.required && !isConditionalRequired) chain += `.min(1, "${field.label || field.name} is required")`;
        else chain += '.optional()';
    }

    if (isConditionalRequired) {
      conditionalRequiredFields.push({
        name: field.name,
        label: field.label || field.name,
        condition: field.condition!,
      });
    }

    lines.push(`  ${field.name}: ${chain},`);
  }

  lines.push('});');

  // Generate .superRefine() if there are conditional required fields
  if (conditionalRequiredFields.length > 0) {
    lines.push('');
    lines.push('export const formSchema = baseSchema.superRefine((data, ctx) => {');
    for (const crf of conditionalRequiredFields) {
      const { condition } = crf;
      let conditionExpr = '';
      switch (condition.operator) {
        case 'isTrue':
          conditionExpr = `data.${condition.field} === true`;
          break;
        case 'isFalse':
          conditionExpr = `!data.${condition.field}`;
          break;
        case 'equals':
          conditionExpr = `data.${condition.field} === "${condition.value}"`;
          break;
        case 'notEquals':
          conditionExpr = `data.${condition.field} !== "${condition.value}"`;
          break;
        case 'notEmpty':
          conditionExpr = `!!data.${condition.field} && data.${condition.field} !== ""`;
          break;
        case 'empty':
          conditionExpr = `!data.${condition.field} || data.${condition.field} === ""`;
          break;
        case 'contains':
          conditionExpr = `String(data.${condition.field} || "").includes("${condition.value || ""}")`;
          break;
        case 'in':
          conditionExpr = `[${(condition.value || "").split(",").map(v => `"${v.trim()}"`).join(", ")}].includes(String(data.${condition.field}))`;
          break;
        default:
          conditionExpr = `true`;
      }
      lines.push(`  if (${conditionExpr}) {`);
      lines.push(`    if (!data.${crf.name} || (typeof data.${crf.name} === "string" && data.${crf.name}.length === 0)) {`);
      lines.push(`      ctx.addIssue({ code: z.ZodIssueCode.custom, message: "${crf.label} is required", path: ["${crf.name}"] });`);
      lines.push(`    }`);
      lines.push(`  }`);
    }
    lines.push('});');
  } else {
    lines.push('');
    lines.push('export const formSchema = baseSchema;');
  }

  lines.push('');
  lines.push('export type FormValues = z.infer<typeof formSchema>;');
  return lines.join('\n');
}

/**
 * Utility for handling extra keys from async/infinite field selections.
 * 
 * When an async/infinite field fetches data like { id, city_code, name }
 * and maps label=name, value=id, extra keys like city_code are stored
 * as "{fieldName}__{keyName}" in form state so other fields can watch them.
 */

import type { FieldOption } from "../types/types";

type FieldOptionWithRaw = FieldOption & {
  _raw?: Record<string, unknown>;
};

/**
 * Given a selected option with _raw metadata, returns a map of
 * extra key form values to set: { "fieldName__city_code": "KTM", ... }
 */
export function getExtraKeyValues(
  fieldName: string,
  option: FieldOption | undefined
): Record<string, unknown> {
  if (!option) return {};

  const extendedOption = option as FieldOptionWithRaw;
  const raw = extendedOption._raw;

  if (!raw || typeof raw !== "object") return {};

  const result: Record<string, unknown> = {};
  
  for (const [key, val] of Object.entries(raw)) {
    result[`${fieldName}__${key}`] = val;
  }

  return result;
}

/**
 * For multi-select fields, aggregate extra keys from all selected options.
 * Values are flattened into comma-separated strings to stay compatible with text watchers.
 */
export function getExtraKeyValuesFromOptions(
  fieldName: string,
  options: FieldOption[]
): Record<string, unknown> {
  const grouped = new Map<string, string[]>();

  for (const option of options) {
    const raw = (option as FieldOptionWithRaw)._raw;
    if (!raw || typeof raw !== "object") continue;
    for (const [key, val] of Object.entries(raw)) {
      const text = val == null ? "" : String(val);
      if (!grouped.has(key)) grouped.set(key, []);
      if (text) grouped.get(key)!.push(text);
    }
  }

  const result: Record<string, unknown> = {};
  for (const [key, values] of grouped.entries()) {
    result[`${fieldName}__${key}`] = values.join(", ");
  }
  return result;
}

import type { FieldOption, FormFieldConfig, WatchTransform } from "../types/types";

/** Field types that store string[] in form state. */
const MULTI_STRING_VALUE_TYPES = new Set<FormFieldConfig["type"]>([
  "multiselect",
  "multicombobox",
  "asyncmultiselect",
  "asyncmulticombobox",
  "infinitemultiselect",
  "infinitemulticombobox",
  "checkboxgroup",
]);

export function isMultiStringFieldType(type: FormFieldConfig["type"]): boolean {
  return MULTI_STRING_VALUE_TYPES.has(type);
}

/** Keys to try against watchConfig.valueMap (arrays also try JSON.stringify). */
export function valueMapLookupKeys(watched: unknown): string[] {
  if (watched === undefined || watched === null) return [""];
  const keys: string[] = [String(watched)];
  if (Array.isArray(watched)) {
    try {
      keys.push(JSON.stringify(watched));
    } catch {
      /* ignore */
    }
  }
  return keys;
}

/**
 * Base string from the watched raw value before transforms:
 * uses valueMap when present, otherwise sensible string coercion.
 */
export function pickWatchBaseString(
  watched: unknown,
  valueMap?: Record<string, string>,
): string {
  if (valueMap) {
    for (const k of valueMapLookupKeys(watched)) {
      if (Object.prototype.hasOwnProperty.call(valueMap, k)) {
        return valueMap[k]!;
      }
    }
  }
  if (watched === undefined || watched === null) return "";
  if (typeof watched === "string") return watched;
  if (typeof watched === "number" || typeof watched === "boolean") return String(watched);
  if (Array.isArray(watched)) return watched.map(String).join(",");
  try {
    return JSON.stringify(watched);
  } catch {
    return "";
  }
}

export function applyWatchTransform(value: string, transform: WatchTransform): string {
  let result = value || "";

  if (transform.filter === "numbers") result = result.replace(/[^0-9]/g, "");
  else if (transform.filter === "letters") result = result.replace(/[^a-zA-Z\s]/g, "");
  else if (transform.filter === "alphanumeric") result = result.replace(/[^a-zA-Z0-9]/g, "");

  if (transform.slice) {
    result = result.slice(transform.slice.start, transform.slice.end);
  }

  if (transform.case === "upper") result = result.toUpperCase();
  else if (transform.case === "lower") result = result.toLowerCase();
  else if (transform.case === "capitalize")
    result = result.charAt(0).toUpperCase() + result.slice(1).toLowerCase();
  else if (transform.case === "title")
    result = result.replace(
      /\w\S*/g,
      (t) => t.charAt(0).toUpperCase() + t.slice(1).toLowerCase(),
    );

  if (transform.template) {
    result = transform.template.replace("{value}", result);
  }

  return result;
}

/**
 * Maps watched form state + watchConfig into the value to write into the target field
 * (correct primitive / string[] shape for multi-select targets).
 */
export function resolveWatchPopulateValue(
  fieldConfig: Pick<FormFieldConfig, "type" | "name">,
  watchedRaw: unknown,
  wc: NonNullable<FormFieldConfig["watchConfig"]>,
): unknown {
  let mapped = pickWatchBaseString(watchedRaw, wc.valueMap);
  if (wc.transform) {
    mapped = applyWatchTransform(mapped, wc.transform);
  }

  if (isMultiStringFieldType(fieldConfig.type)) {
    if (Array.isArray(watchedRaw)) {
      return watchedRaw.map((x) => String(x)).filter((s) => s !== "");
    }
    if (mapped === "") return [];
    return mapped
      .split(",")
      .map((s) => s.trim())
      .filter(Boolean);
  }

  if (fieldConfig.type === "number") {
    const n = Number(mapped);
    return Number.isFinite(n) ? n : "";
  }

  return mapped;
}

/** Empty / reset value when clearing dependent fields or hiding conditional fields. */
export function emptyValueForFieldType(type: FormFieldConfig["type"]): unknown {
  if (isMultiStringFieldType(type)) return [];
  if (type === "number") return "";
  if (type === "checkbox") return false;
  if (type === "switch") return false;
  return "";
}

export function resetFieldValueForConfig(config: Pick<FormFieldConfig, "type" | "defaultValue">): unknown {
  if (config.defaultValue !== undefined && config.defaultValue !== null) {
    return config.defaultValue;
  }
  return emptyValueForFieldType(config.type);
}

/** Radix Select / Command: ensure externally set value (e.g. watch) still has a matching option row. */
/** Coerce stored form values and API option values to the same string shape for Radix Select / Command. */
export function optionValueKey(v: unknown): string {
  if (v === undefined || v === null) return "";
  return String(v);
}

export function optionValuesEqual(a: unknown, b: unknown): boolean {
  return optionValueKey(a) === optionValueKey(b);
}

export function mergeGhostOptionForSingle(
  options: FieldOption[],
  current: unknown,
): FieldOption[] {
  const key = optionValueKey(current);
  if (!key) return options;
  if (options.some((o) => optionValuesEqual(o.value, key))) return options;
  return [{ value: key, label: String(current) }, ...options];
}

export function mergeGhostOptionsForMultiValues(
  options: FieldOption[],
  selected: string[],
): FieldOption[] {
  const keys = selected.map((v) => optionValueKey(v)).filter(Boolean);
  const missing = keys.filter((k) => !options.some((o) => optionValuesEqual(o.value, k)));
  if (missing.length === 0) return options;
  const ghosts = missing.map((v) => ({ value: v, label: String(v) }));
  return [...ghosts, ...options];
}

import type { AxiosRequestConfig } from "axios";

import type { AsyncApiConfig } from "../types/types";

/** Placeholder replaced with the serialized watched field value (dependent API). */
export const DEPENDENCY_VALUE_TOKEN = "{value}";

/** Serialize a watched form value for URL/body substitution (arrays → comma-separated). */
export function serializeWatchValue(watch: unknown): string {
  if (watch === undefined || watch === null) return "";
  if (Array.isArray(watch)) return watch.map(String).join(",");
  return String(watch);
}

export function substituteDependencyToken(input: string, replacement: string): string {
  if (!input.includes(DEPENDENCY_VALUE_TOKEN)) return input;
  return input.split(DEPENDENCY_VALUE_TOKEN).join(replacement);
}

/**
 * REST-style path segments: `/:id`, `/:value` (before `?` or end of path).
 * Replaced with `encodeURIComponent` of the watched value so country/city URLs stay valid.
 * Use after `{value}` substitution, or instead of `{value}` in the path segment.
 */
export function substitutePathParamPlaceholders(url: string, replacement: string): string {
  const raw = String(replacement ?? "");
  if (!raw || (!url.includes("/:id") && !url.includes("/:value"))) return url;
  const enc = encodeURIComponent(raw);
  const qIdx = url.indexOf("?");
  const path = qIdx === -1 ? url : url.slice(0, qIdx);
  const rest = qIdx === -1 ? "" : url.slice(qIdx);
  const newPath = path
    .replace(/\/:id(?=\/|\?|$)/g, `/${enc}`)
    .replace(/\/:value(?=\/|\?|$)/g, `/${enc}`);
  return newPath + rest;
}

function deepSubstitute(value: unknown, replacement: string): unknown {
  if (value === null || value === undefined) return value;
  if (typeof value === "string") return substituteDependencyToken(value, replacement);
  if (typeof value !== "object") return value;
  if (Array.isArray(value)) return value.map((v) => deepSubstitute(v, replacement));
  const out: Record<string, unknown> = {};
  for (const [k, v] of Object.entries(value as Record<string, unknown>)) {
    const nk = substituteDependencyToken(k, replacement);
    out[nk] = deepSubstitute(v, replacement);
  }
  return out;
}

function hasMeaningfulPayload(payload: unknown): boolean {
  if (payload === undefined || payload === null) return false;
  if (typeof payload !== "object") return true;
  if (Array.isArray(payload)) return payload.length > 0;
  return Object.keys(payload as Record<string, unknown>).length > 0;
}

/** Flatten a JSON-like object into axios query params (primitives only; objects JSON-stringified). */
export function flattenPayloadToQueryParams(
  payload: Record<string, unknown>
): Record<string, string | number | boolean> {
  const out: Record<string, string | number | boolean> = {};
  for (const [k, v] of Object.entries(payload)) {
    if (v === null || v === undefined) continue;
    if (typeof v === "string" || typeof v === "number" || typeof v === "boolean") {
      out[k] = v;
    } else {
      out[k] = JSON.stringify(v);
    }
  }
  return out;
}

/**
 * Applies `{value}` substitution from `_watchValue` to url, headers, and payload.
 * Call before building the axios config; keep `_watchValue` on the returned object for query keys.
 */
export function resolveAsyncApiConfigForFetch(api: AsyncApiConfig): AsyncApiConfig {
  const replacement = serializeWatchValue(api._watchValue);
  const url = substitutePathParamPlaceholders(
    substituteDependencyToken(api.url ?? "", replacement),
    replacement,
  );
  const headers = api.headers
    ? Object.fromEntries(
        Object.entries(api.headers).map(([k, v]) => [
          substituteDependencyToken(k, replacement),
          substituteDependencyToken(v, replacement),
        ]),
      )
    : undefined;
  const payload =
    api.payload === undefined || api.payload === null
      ? undefined
      : (deepSubstitute(api.payload, replacement) as Record<string, unknown> | unknown[]);

  return { ...api, url, headers, payload: payload as AsyncApiConfig["payload"] };
}

const BODY_METHODS = new Set(["POST", "PUT", "PATCH"]);

function methodUsesJsonBody(
  method: AsyncApiConfig["method"],
  originalPayload: AsyncApiConfig["payload"],
): boolean {
  if (BODY_METHODS.has(method)) return true;
  if (method === "DELETE" && hasMeaningfulPayload(originalPayload)) return true;
  return false;
}

/**
 * Builds axios config for async/infinite option fetches.
 * - GET (and DELETE without a meaningful payload): `payload` is merged into **query params** with `dynamicParams`.
 * - POST / PUT / PATCH, and DELETE with a payload: JSON body = substituted `payload` + `dynamicParams`.
 *   If there was no user payload, injects `{ value: <watch> }` so POST dependent calls work without an explicit body.
 */
export function buildAxiosConfigForAsyncApi(
  apiConfig: AsyncApiConfig,
  dynamicParams: Record<string, string | number> = {},
): AxiosRequestConfig {
  const resolved = resolveAsyncApiConfigForFetch(apiConfig);
  const method = resolved.method;
  const repl = serializeWatchValue(apiConfig._watchValue);
  const hadUserPayload = hasMeaningfulPayload(apiConfig.payload);

  if (methodUsesJsonBody(method, apiConfig.payload)) {
    if (Array.isArray(resolved.payload)) {
      return {
        url: resolved.url,
        method,
        headers: resolved.headers,
        data: resolved.payload,
      };
    }
    let body: Record<string, unknown> =
      resolved.payload && typeof resolved.payload === "object" && !Array.isArray(resolved.payload)
        ? { ...(resolved.payload as Record<string, unknown>) }
        : {};
    if (!hadUserPayload && repl) {
      body = { value: repl, ...body };
    }
    return {
      url: resolved.url,
      method,
      headers: resolved.headers,
      data: { ...body, ...dynamicParams },
    };
  }

  const queryFromPayload =
    resolved.payload &&
    typeof resolved.payload === "object" &&
    !Array.isArray(resolved.payload)
      ? flattenPayloadToQueryParams(resolved.payload as Record<string, unknown>)
      : {};

  return {
    url: resolved.url,
    method,
    headers: resolved.headers,
    params: { ...queryFromPayload, ...dynamicParams },
  };
}

