"use client";

import { ChevronLeft, ChevronRight, AlertCircle, Check, AlertTriangle, X } from "lucide-react";

import { cn } from "@/lib/utils";
import { useReactHookForm } from "./useReactHookForm";
import type { FormConfig, FormSubmitHandler, ReactHookFormZodSchema } from "../types/types";

import { Form } from "@/components/ui/form";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Progress } from "@/components/ui/progress";
import { Separator } from "@/components/ui/separator";
import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";

import { ReactHookFormField } from "./ReactHookFormField";

interface ReactHookFormProps {
  config: FormConfig;
  onSubmit: FormSubmitHandler;
  className?: string;
  /** Zod schema for validation — pass a static schema (use .refine() for conditional logic). */
  schema: ReactHookFormZodSchema;
  /** Override default values (merged on top of config defaults). */
  initialValues?: Record<string, unknown>;
}

export function ReactHookForm({ config, onSubmit, className, schema, initialValues }: ReactHookFormProps) {
  const {
    form,
    activeTab,
    globalError,
    currentStep,
    handleSubmit,
    setActiveTab,
    setGlobalError,
    setCurrentStep,
    validateSection,
    handleTabChange,
    isSectionComplete,
    getOverallProgress,
    getSectionErrorCount,
  } = useReactHookForm({ config, schema, onSubmit, initialValues });

  const layout = config.layout || "single";
  const totalSteps = config.sections.length;

  const renderSectionFields = (sectionIndex: number) => {
    const section = config.sections[sectionIndex];
    if (!section) return null;
    return (
      <div
        className={cn(
          "grid gap-4",
          section.columns === 2 && "md:grid-cols-2",
          section.columns === 3 && "md:grid-cols-3",
          section.columns === 4 && "md:grid-cols-4"
        )}
      >
        {section.fields.map((field) => (
          <div
            key={field.name}
            style={field.colSpan && field.colSpan > 1 ? { gridColumn: `span ${field.colSpan}` } : undefined}
          >
            <ReactHookFormField config={field} />
          </div>
        ))}
      </div>
    );
  };

  const renderGlobalError = () => {
    if (!globalError) return null;
    return (
      <Alert variant="destructive" className="mb-4">
        <AlertTriangle className="h-4 w-4" />
        <AlertTitle>Server Error</AlertTitle>
        <AlertDescription className="flex items-center justify-between">
          <span>{globalError}</span>
          <Button variant="ghost" size="icon" className="h-6 w-6 shrink-0" onClick={() => setGlobalError(null)}>
            <X className="h-3 w-3" />
          </Button>
        </AlertDescription>
      </Alert>
    );
  };

  // ─── SINGLE LAYOUT ───
  if (layout === "single") {
    return (
      <Form {...form}>
        <form onSubmit={handleSubmit} className={cn("space-y-6", className)}>
          {renderGlobalError()}
          {config.title && (
            <div className="space-y-2">
              <h2 className="text-2xl font-bold tracking-tight">{config.title}</h2>
              {config.description && <p className="text-muted-foreground">{config.description}</p>}
            </div>
          )}
          {config.sections.map((section, sectionIndex) => (
            <Card key={section.id}>
              {(section.title || section.description) && (
                <CardHeader>
                  {section.title && <CardTitle>{section.title}</CardTitle>}
                  {section.description && <CardDescription>{section.description}</CardDescription>}
                </CardHeader>
              )}
              <CardContent className={!section.title && !section.description ? "pt-6" : ""}>
                {renderSectionFields(sectionIndex)}
              </CardContent>
              {sectionIndex < config.sections.length - 1 && <Separator />}
            </Card>
          ))}
          <div className="flex gap-4">
            <Button type="submit" disabled={form.formState.isSubmitting}>
              {form.formState.isSubmitting ? "Submitting..." : config.submitLabel || "Submit"}
            </Button>
            {config.showReset && (
              <Button type="button" variant="outline" onClick={() => form.reset()}>
                {config.resetLabel || "Reset"}
              </Button>
            )}
          </div>
        </form>
      </Form>
    );
  }

  // ─── COMPACT LAYOUT ───
  if (layout === "compact") {
    return (
      <Form {...form}>
        <form onSubmit={handleSubmit} className={cn("space-y-4", className)}>
          {renderGlobalError()}
          {config.sections.map((section, sectionIndex) => (
            <div key={section.id}>{renderSectionFields(sectionIndex)}</div>
          ))}
          <div className="flex gap-4">
            <Button type="submit" className="w-full" disabled={form.formState.isSubmitting}>
              {form.formState.isSubmitting ? "Submitting..." : config.submitLabel || "Submit"}
            </Button>
          </div>
        </form>
      </Form>
    );
  }

  // ─── MULTI-TAB LAYOUT ───
  if (layout === "multi-tab") {
    const currentIndex = config.sections.findIndex(s => s.id === activeTab);
    const isFirst = currentIndex <= 0;
    const isLast = currentIndex >= config.sections.length - 1;

    return (
      <Form {...form}>
        <form onSubmit={handleSubmit} className={cn("space-y-0", className)}>
          {renderGlobalError()}
          <Tabs value={activeTab} onValueChange={handleTabChange} className="w-full">
            <div className="bg-muted/30 border border-border rounded-t-lg px-2 pt-2">
              <TabsList className="h-auto bg-transparent p-0 gap-0 w-full justify-start flex-wrap">
                {config.sections.map((section, idx) => {
                  const errorCount = getSectionErrorCount(idx);
                  const completed = isSectionComplete(idx);
                  const isActive = section.id === activeTab;
                  return (
                    <TabsTrigger
                      key={section.id}
                      value={section.id}
                      className="rounded-b-none border-b-2 border-transparent data-[state=active]:border-primary data-[state=active]:bg-transparent data-[state=active]:shadow-none px-4 py-2.5 text-sm font-medium gap-2"
                    >
                      {completed && !isActive && (
                        <div className="h-4 w-4 rounded-full bg-primary flex items-center justify-center shrink-0">
                          <Check className="h-2.5 w-2.5 text-primary-foreground" />
                        </div>
                      )}
                      {section.title || section.id}
                      {errorCount > 0 && (
                        <Badge variant="destructive" className="h-5 px-1.5 text-[10px] gap-1">
                          <AlertCircle className="h-3 w-3" />
                          {errorCount}
                        </Badge>
                      )}
                    </TabsTrigger>
                  );
                })}
              </TabsList>
            </div>

            <div className="border border-t-0 border-border rounded-b-lg">
              {config.sections.map((section, sectionIndex) => (
                <TabsContent key={section.id} value={section.id} className="mt-0 p-6">
                  {(section.title || section.description) && (
                    <div className="mb-6">
                      {section.title && <h3 className="text-lg font-semibold">{section.title}</h3>}
                      {section.description && <p className="text-sm text-muted-foreground mt-1">{section.description}</p>}
                    </div>
                  )}
                  {renderSectionFields(sectionIndex)}
                </TabsContent>
              ))}
              <Separator />
              <div className="flex items-center justify-between p-4">
                <Button type="button" variant="secondary" onClick={() => form.reset()}>Cancel</Button>
                <div className="flex items-center gap-2">
                  <Button type="button" variant="ghost" disabled={isFirst}
                    onClick={() => { if (currentIndex > 0) setActiveTab(config.sections[currentIndex - 1].id); }}
                  >
                    <ChevronLeft className="h-4 w-4 mr-1" />Previous
                  </Button>
                  {isLast ? (
                    <Button type="submit" disabled={form.formState.isSubmitting}>
                      {form.formState.isSubmitting ? "Submitting..." : config.submitLabel || "Submit"}
                    </Button>
                  ) : (
                    <Button type="button" onClick={async () => {
                      const valid = await validateSection(currentIndex);
                      if (valid && currentIndex < config.sections.length - 1) {
                        setActiveTab(config.sections[currentIndex + 1].id);
                      }
                    }}>
                      Next<ChevronRight className="h-4 w-4 ml-1" />
                    </Button>
                  )}
                </div>
              </div>
            </div>
          </Tabs>
        </form>
      </Form>
    );
  }

  // ─── WIZARD LAYOUT ───
  if (layout === "wizard") {
    const currentSection = config.sections[currentStep];
    const progress = getOverallProgress();
    return (
      <Form {...form}>
        <form onSubmit={handleSubmit} className={cn("space-y-6", className)}>
          {renderGlobalError()}
          {config.title && (
            <div className="space-y-2">
              <h2 className="text-2xl font-bold tracking-tight">{config.title}</h2>
              {config.description && <p className="text-muted-foreground">{config.description}</p>}
            </div>
          )}

          {/* Progress bar */}
          <div className="space-y-1">
            <div className="flex items-center justify-between text-xs text-muted-foreground">
              <span>Step {currentStep + 1} of {totalSteps}</span>
              <span>{progress}% complete</span>
            </div>
            <Progress value={progress} className="h-2" />
          </div>

          {/* Step indicators */}
          <div className="flex items-center justify-between">
            {config.sections.map((section, idx) => {
              const errorCount = getSectionErrorCount(idx);
              const completed = isSectionComplete(idx);
              return (
                <div key={section.id} className="flex items-center gap-2 flex-1">
                  <div className={cn(
                    "h-8 w-8 rounded-full flex items-center justify-center text-sm font-medium border-2 transition-all shrink-0 relative",
                    completed && idx < currentStep ? "bg-primary border-primary text-primary-foreground"
                      : idx === currentStep ? "border-primary text-primary bg-background"
                      : idx < currentStep ? "bg-primary border-primary text-primary-foreground"
                      : "border-muted text-muted-foreground"
                  )}>
                    {completed && idx < currentStep ? (
                      <Check className="h-4 w-4" />
                    ) : (
                      idx + 1
                    )}
                    {errorCount > 0 && (
                      <Badge variant="destructive" className="absolute -top-2 -right-2 h-4 w-4 p-0 text-[9px] flex items-center justify-center">
                        {errorCount}
                      </Badge>
                    )}
                  </div>
                  <span className={cn("text-xs font-medium hidden sm:block truncate",
                    idx <= currentStep ? "text-foreground" : "text-muted-foreground"
                  )}>
                    {section.title || `Step ${idx + 1}`}
                  </span>
                  {idx < config.sections.length - 1 && (
                    <div className={cn("flex-1 h-0.5 mx-2", idx < currentStep ? "bg-primary" : "bg-muted")} />
                  )}
                </div>
              );
            })}
          </div>

          <Card>
            {(currentSection?.title || currentSection?.description) && (
              <CardHeader>
                {currentSection.title && <CardTitle>{currentSection.title}</CardTitle>}
                {currentSection.description && <CardDescription>{currentSection.description}</CardDescription>}
              </CardHeader>
            )}
            <CardContent className={!currentSection?.title && !currentSection?.description ? "pt-6" : ""}>
              {renderSectionFields(currentStep)}
            </CardContent>
          </Card>
          <div className="flex items-center justify-between">
            <Button type="button" variant="outline" disabled={currentStep === 0}
              onClick={() => setCurrentStep(Math.max(0, currentStep - 1))}
            >
              <ChevronLeft className="h-4 w-4 mr-1" />Previous
            </Button>
            {currentStep < totalSteps - 1 ? (
              <Button type="button" onClick={async () => {
                const valid = await validateSection(currentStep);
                if (valid) setCurrentStep(Math.min(totalSteps - 1, currentStep + 1));
              }}>
                Next<ChevronRight className="h-4 w-4 ml-1" />
              </Button>
            ) : (
              <Button type="submit" disabled={form.formState.isSubmitting}>
                {form.formState.isSubmitting ? "Submitting..." : config.submitLabel || "Submit"}
              </Button>
            )}
          </div>
        </form>
      </Form>
    );
  }

  return null;
}

"use client";

import { useEffect, useMemo } from "react";
import { AlertTriangle } from "lucide-react";
import { useFormContext } from "react-hook-form";

import type {
  FormFieldConfig,
  FieldOption,
} from "../types/types";
import {
  resetFieldValueForConfig,
  resolveWatchPopulateValue,
} from "../utils/watchPopulate";
import {
  hasDependentApiConfig,
  hasOptions,
  hasWatchValue,
} from "../utils/formFieldGuards";

import {
  FileField,
  DateField,
  TextField,
  TextareaField,
  SelectField,
  RadioField,
  CheckboxField,
  CheckboxGroupField,
  SwitchField,
  SwitchGroupField,
  ComboboxField,
  MultiselectField,
  MultiComboboxField,
  AsyncSelectField,
  AsyncMultiSelectField,
  AsyncComboboxField,
  AsyncMultiComboboxField,
  InfiniteSelectField,
  InfiniteMultiSelectField,
  InfiniteComboboxField,
  InfiniteMultiComboboxField,
  EmptyField,
  PreviewField,
} from "./fields";
import { Alert, AlertDescription } from "@/components/ui/alert";
import { FormFieldErrorBoundary, validateFieldConfig } from "../FormFieldErrorBoundary";

interface ReactHookFormFieldProps {
  config: FormFieldConfig;
}

export function ReactHookFormField({ config }: ReactHookFormFieldProps) {
  const validationError = validateFieldConfig(config);
  const form = useFormContext();

  // Conditional visibility
  const conditionFieldName = config.condition?.field;
  const conditionValue = conditionFieldName
    ? form.watch(conditionFieldName)
    : undefined;

  // Watch auto-populate
  const watchFieldName = config.watchConfig?.watchField;
  const watchedValue = watchFieldName ? form.watch(watchFieldName) : undefined;

  // Dependent options
  const depFieldName = config.dependentOptions?.watchField;
  const depValue = depFieldName ? form.watch(depFieldName) : undefined;
  const depApiWatchField = hasDependentApiConfig(config)
    ? config.dependentApiConfig?.watchField
    : undefined;
  const depApiWatchValue = depApiWatchField
    ? form.watch(depApiWatchField)
    : undefined;

  useEffect(() => {
    if (!config.watchConfig || !watchFieldName) return;
    const next = resolveWatchPopulateValue(config, watchedValue, config.watchConfig);
    form.setValue(config.name, next, { shouldDirty: false });
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [watchedValue, watchFieldName, config.name, config.type]);

  // Clear dependent field when parent changes
  useEffect(() => {
    if (!config.dependentOptions || !depFieldName) return;
    form.setValue(config.name, resetFieldValueForConfig(config), { shouldDirty: false });
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [depValue]);

  // Clear field when dependent API watch field changes
  useEffect(() => {
    if (!hasDependentApiConfig(config) || !config.dependentApiConfig || !depApiWatchField) return;
    form.setValue(config.name, resetFieldValueForConfig(config), { shouldDirty: false });
  }, [depApiWatchValue]);

  // Resolve dependent options
  const resolvedConfig = useMemo((): FormFieldConfig => {
    let cfg = config;
    // Static dependent options
    if (cfg.dependentOptions && depValue) {
      const matchedOptions: FieldOption[] =
        cfg.dependentOptions.optionsMap[String(depValue)] || [];
      if (hasOptions(cfg)) {
        cfg = { ...cfg, options: matchedOptions };
      }
    }

    if (
      hasDependentApiConfig(cfg) &&
      cfg.dependentApiConfig &&
      hasWatchValue(depApiWatchValue)
    ) {
      const depApi = cfg.dependentApiConfig;
      const apiConfig = {
        ...depApi,
        _watchValue: depApiWatchValue,
      };
      cfg = { ...cfg, apiConfig } as FormFieldConfig;
    }
    return cfg;
  }, [config, depValue, depApiWatchValue]);

  // Evaluate condition
  const visible = (() => {
    if (!config.condition || !conditionFieldName) return true;
    const { operator, value } = config.condition;
    switch (operator) {
      case "equals":
        return String(conditionValue) === String(value);
      case "notEquals":
        return String(conditionValue) !== String(value);
      case "contains":
        return String(conditionValue || "").includes(value || "");
      case "notEmpty":
        return !!conditionValue && conditionValue !== "";
      case "empty":
        return !conditionValue || conditionValue === "";
      case "in":
        return (value || "")
          .split(",")
          .map((v: string) => v.trim())
          .includes(String(conditionValue));
      case "isTrue":
        return conditionValue === true || conditionValue === "true";
      case "isFalse":
        return (
          conditionValue === false ||
          conditionValue === "false" ||
          !conditionValue
        );
      default:
        return true;
    }
  })();

  // Clear field value when conditionally hidden
  useEffect(() => {
    if (!visible && config.condition) {
      form.setValue(config.name, resetFieldValueForConfig(config), {
        shouldDirty: false,
        shouldValidate: false,
      });
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [visible]);

  if (!visible) return null;

  if (validationError) {
    return (
      <Alert variant="destructive" className="py-2">
        <AlertTriangle className="h-3.5 w-3.5" />
        <AlertDescription className="text-xs">{validationError}</AlertDescription>
      </Alert>
    );
  }

  // ─── Field type → Component mapping ───
  const renderField = () => {
    try {
      switch (resolvedConfig.type) {
        case "text":
        case "email":
        case "password":
        case "tel":
        case "url":
          return <TextField config={resolvedConfig} />;
        case "number":
          return <TextField config={resolvedConfig} />;
        case "textarea":
          return <TextareaField config={resolvedConfig} />;
        case "select":
          return <SelectField config={resolvedConfig} />;
        case "asyncselect":
          return <AsyncSelectField config={resolvedConfig} />;
        case "infiniteselect":
          return <InfiniteSelectField config={resolvedConfig} />;
        case "combobox":
          return <ComboboxField config={resolvedConfig} />;
        case "asynccombobox":
          return <AsyncComboboxField config={resolvedConfig} />;
        case "infinitecombobox":
          return <InfiniteComboboxField config={resolvedConfig} />;
        case "multiselect":
          return <MultiselectField config={resolvedConfig} />;
        case "asyncmultiselect":
          return <AsyncMultiSelectField config={resolvedConfig} />;
        case "infinitemultiselect":
          return <InfiniteMultiSelectField config={resolvedConfig} />;
        case "multicombobox":
          return <MultiComboboxField config={resolvedConfig} />;
        case "asyncmulticombobox":
          return <AsyncMultiComboboxField config={resolvedConfig} />;
        case "infinitemulticombobox":
          return <InfiniteMultiComboboxField config={resolvedConfig} />;
        case "radio":
          return <RadioField config={resolvedConfig} />;
        case "checkbox":
          return <CheckboxField config={resolvedConfig} />;
        case "checkboxgroup":
          return <CheckboxGroupField config={resolvedConfig} />;
        case "switch":
          return <SwitchField config={resolvedConfig} />;
        case "switchgroup":
          return <SwitchGroupField config={resolvedConfig} />;
        case "file":
          return <FileField config={resolvedConfig} />;
        case "date":
          return <DateField config={resolvedConfig} />;
        case "empty":
          return <EmptyField config={resolvedConfig} />;
        case "preview":
          return <PreviewField config={resolvedConfig} />;
        case "hidden":
          return null;
        default:
          return null;
      }
    } catch (e) {
      console.error(
        `[GenericFormField] Error rendering field "${config.name}":`,
        e,
      );
      return null;
    }
  };
  return (
    <FormFieldErrorBoundary fieldName={config.name}>
      {renderField()}
    </FormFieldErrorBoundary>
  );
}

