/** Time scroll picker component */
function TimeScroller({
  value,
  items,
  onChange,
  label,
}: {
  value: number;
  items: readonly number[];
  onChange: (v: number) => void;
  label: string;
}) {
  const ref = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (ref.current) {
