                          value={is12h ? displayHour : hours}
                          items={is12h ? HOUR_12_ITEMS : HOUR_24_ITEMS}
                          onChange={handleHourChange}
                          label="Hr"
                        />
                        <TimeScroller
                          value={minutes}
                          items={MIN_60_ITEMS}
                          onChange={(m) => setTime(hours, m, seconds)}
